                    switch (value) {
                    case .matrix:
                        NavigationLink(destination: DigitalRain()) {
                            Text("\(value.rawValue)")
                                .foregroundStyle(.primary)
                        }
                    case .clock:
                        NavigationLink(destination: ClockView()) {
                            Text("\(value.rawValue)")
                                .foregroundStyle(.primary)
